// Kafka Producer Configuration
@Configuration
class KafkaProducerConfig {

    @Bean
    public KafkaEventProducer kafkaEventProducer() {
        Properties props = new Properties();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.ACKS_CONFIG, "all");
        props.put(ProducerConfig.RETRIES_CONFIG, 3);
        props.put(ProducerConfig.ENABLE_IDEMPOTENCE_CONFIG, true);
        props.put(ProducerConfig.MAX_IN_FLIGHT_REQUESTS_PER_CONNECTION, 5);

        KafkaProducer<String, String> producer = new KafkaProducer<>(props);
        return new KafkaEventProducer(producer);
    }
}

// Kafka Event Producer Service
class KafkaEventProducer {

    private final KafkaProducer<String, String> producer;
    private static final String DEFAULT_TOPIC = "event-tracking";

    public KafkaEventProducer(KafkaProducer<String, String> producer) {
        this.producer = producer;
    }

    public RecordMetadata sendEvent(String topic, String key, String value, Map<String, String> headers)
            throws ExecutionException, InterruptedException {

        String targetTopic = (topic != null && !topic.isEmpty()) ? topic : DEFAULT_TOPIC;

        ProducerRecord<String, String> record = new ProducerRecord<>(targetTopic, key, value);

        // Inject custom headers into the Kafka message
        if (headers != null) {
            Headers kafkaHeaders = record.headers();
            for (Map.Entry<String, String> entry : headers.entrySet()) {
                kafkaHeaders.add(entry.getKey(), entry.getValue().getBytes(StandardCharsets.UTF_8));
            }
        }

        // Add system-level headers
        record.headers().add("produced-timestamp", String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8));
        record.headers().add("producer-app", "event-tracking-service".getBytes(StandardCharsets.UTF_8));

        Future<RecordMetadata> future = producer.send(record, (metadata, exception) -> {
            if (exception != null) {
                System.err.println("Failed to send message: " + exception.getMessage());
            } else {
                System.out.printf("Message sent to topic=%s partition=%d offset=%d%n",
                        metadata.topic(), metadata.partition(), metadata.offset());
            }
        });

        return future.get();
    }

    @PreDestroy
    public void close() {
        if (producer != null) {
            producer.flush();
            producer.close();
        }
    }
}

