// REST Controller
@RestController
@RequestMapping("/api/events")
class EventTrackingController {

    private final KafkaEventProducer kafkaEventProducer;

    public EventTrackingController(KafkaEventProducer kafkaEventProducer) {
        this.kafkaEventProducer = kafkaEventProducer;
    }

    @PostMapping("/publish")
    public ResponseEntity<EventResponse> publishEvent(
            @RequestBody EventRequest eventRequest,
            @RequestHeader(value = "X-Tracking-Id", required = false) String httpTrackingId,
            @RequestHeader(value = "X-User-Id", required = false) String httpUserId,
            @RequestHeader(value = "X-Source-App", required = false) String sourceApp,
            @RequestHeader(value = "X-Correlation-Id", required = false) String correlationId) {

        EventResponse response = new EventResponse();

        try {
            // Build headers map from both HTTP headers and request body
            Map<String, String> kafkaHeaders = buildKafkaHeaders(eventRequest, httpTrackingId, httpUserId, sourceApp, correlationId);

            String trackingId = kafkaHeaders.get("tracking-id");
            String key = (eventRequest.getKey() != null) ? eventRequest.getKey() : trackingId;

            RecordMetadata metadata = kafkaEventProducer.sendEvent(
                    eventRequest.getTopic(),
                    key,
                    eventRequest.getMessage(),
                    kafkaHeaders
            );

            response.setStatus("SUCCESS");
            response.setTrackingId(trackingId);
            response.setTopic(metadata.topic());
            response.setPartition(metadata.partition());
            response.setOffset(metadata.offset());
            response.setTimestamp(metadata.timestamp());
            response.setMessage("Event published successfully");

            return ResponseEntity.ok(response);

        } catch (ExecutionException | InterruptedException e) {
            Thread.currentThread().interrupt();
            response.setStatus("FAILED");
            response.setMessage("Failed to publish event: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(response);
        }
    }

    @PostMapping("/publish/batch")
    public ResponseEntity<Map<String, Object>> publishBatchEvents(
            @RequestBody List<EventRequest> eventRequests,
            @RequestHeader(value = "X-Tracking-Id", required = false) String httpTrackingId,
            @RequestHeader(value = "X-User-Id", required = false) String httpUserId,
            @RequestHeader(value = "X-Source-App", required = false) String sourceApp) {

        String batchId = UUID.randomUUID().toString();
        java.util.List<EventResponse> results = new java.util.ArrayList<>();
        int successCount = 0;
        int failureCount = 0;

        for (int i = 0; i < eventRequests.size(); i++) {
            EventRequest request = eventRequests.get(i);
            EventResponse response = new EventResponse();

            try {
                Map<String, String> kafkaHeaders = buildKafkaHeaders(request, httpTrackingId, httpUserId, sourceApp, null);
                kafkaHeaders.put("batch-id", batchId);
                kafkaHeaders.put("batch-index", String.valueOf(i));
                kafkaHeaders.put("batch-size", String.valueOf(eventRequests.size()));

                String trackingId = kafkaHeaders.get("tracking-id");
                String key = (request.getKey() != null) ? request.getKey() : trackingId;

                RecordMetadata metadata = kafkaEventProducer.sendEvent(
                        request.getTopic(), key, request.getMessage(), kafkaHeaders);

                response.setStatus("SUCCESS");
                response.setTrackingId(trackingId);
                response.setTopic(metadata.topic());
                response.setPartition(metadata.partition());
                response.setOffset(metadata.offset());
                successCount++;

            } catch (ExecutionException | InterruptedException e) {
                Thread.currentThread().interrupt();
                response.setStatus("FAILED");
                response.setMessage(e.getMessage());
                failureCount++;
            }

            results.add(response);
        }

        Map<String, Object> batchResponse = new HashMap<>();
        batchResponse.put("batchId", batchId);
        batchResponse.put("totalEvents", eventRequests.size());
        batchResponse.put("successCount", successCount);
        batchResponse.put("failureCount", failureCount);
        batchResponse.put("results", results);

        HttpStatus status = (failureCount == 0) ? HttpStatus.OK : HttpStatus.MULTI_STATUS;
        return ResponseEntity.status(status).body(batchResponse);
    }

    @PostMapping("/publish/simple")
    public ResponseEntity<EventResponse> publishSimpleEvent(
            @RequestParam String topic,
            @RequestParam(required = false) String key,
            @RequestBody String message,
            @RequestHeader Map<String, String> allHttpHeaders) {

        EventResponse response = new EventResponse();

        try {
            // Extract all X-Custom-* headers and standard tracking headers
            Map<String, String> kafkaHeaders = new HashMap<>();
            String trackingId = null;

            for (Map.Entry<String, String> entry : allHttpHeaders.entrySet()) {
                String headerName = entry.getKey().toLowerCase();

                if (headerName.equals("x-tracking-id")) {
                    trackingId = entry.getValue();
                    kafkaHeaders.put("tracking-id", entry.getValue());
                } else if (headerName.equals("x-user-id")) {
                    kafkaHeaders.put("user-id", entry.getValue());
                } else if (headerName.equals("x-correlation-id")) {
                    kafkaHeaders.put("correlation-id", entry.getValue());
                } else if (headerName.equals("x-source-app")) {
                    kafkaHeaders.put("source-app", entry.getValue());
                } else if (headerName.startsWith("x-custom-")) {
                    // Map X-Custom-* HTTP headers to Kafka headers
                    String kafkaHeaderName = headerName.substring("x-custom-".length());
                    kafkaHeaders.put(kafkaHeaderName, entry.getValue());
                }
            }

            if (trackingId == null) {
                trackingId = UUID.randomUUID().toString();
                kafkaHeaders.put("tracking-id", trackingId);
            }

            String messageKey = (key != null) ? key : trackingId;

            RecordMetadata metadata = kafkaEventProducer.sendEvent(topic, messageKey, message, kafkaHeaders);

            response.setStatus("SUCCESS");
            response.setTrackingId(trackingId);
            response.setTopic(metadata.topic());
            response.setPartition(metadata.partition());
            response.setOffset(metadata.offset());
            response.setTimestamp(metadata.timestamp());
            response.setMessage("Event published successfully");

            return ResponseEntity.ok(response);

        } catch (ExecutionException | InterruptedException e) {
            Thread.currentThread().interrupt();
            response.setStatus("FAILED");
            response.setMessage("Failed to publish event: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(response);
        }
    }

    private Map<String, String> buildKafkaHeaders(
            EventRequest eventRequest,
            String httpTrackingId,
            String httpUserId,
            String sourceApp,
            String correlationId) {

        Map<String, String> kafkaHeaders = new HashMap<>();

        // Priority: request body > HTTP headers > auto-generated

        // Tracking ID
        String trackingId = eventRequest.getTrackingId();
        if (trackingId == null || trackingId.isEmpty()) {
            trackingId = httpTrackingId;
        }
        if (trackingId == null || trackingId.isEmpty()) {
            trackingId = UUID.randomUUID().toString();
        }
        kafkaHeaders.put("tracking-id", trackingId);

        // User ID
        String userId = eventRequest.getUserId();
        if (userId == null || userId.isEmpty()) {
            userId = httpUserId;
        }
        if (userId != null && !userId.isEmpty()) {
            kafkaHeaders.put("user-id", userId);
        }

        // Event Type
        if (eventRequest.getEventType() != null && !eventRequest.getEventType().isEmpty()) {
            kafkaHeaders.put("event-type", eventRequest.getEventType());
        }

        // Source App
        if (sourceApp != null && !sourceApp.isEmpty()) {
            kafkaHeaders.put("source-app", sourceApp);
        }

        // Correlation ID
        if (correlationId != null && !correlationId.isEmpty()) {
            kafkaHeaders.put("correlation-id", correlationId);
        }

        // Custom metadata from request body
        if (eventRequest.getCustomMetadata() != null) {
            for (Map.Entry<String, String> entry : eventRequest.getCustomMetadata().entrySet()) {
                kafkaHeaders.put("custom-" + entry.getKey(), entry.getValue());
            }
        }

        return kafkaHeaders;
    }
}

